3319	\begin{definition}\leanok
3320	[Transport of a slice presentation to a geometric presentation]
3321	  \label{def:over_restrict_presentation}
3322	  \lean{AlgebraicGeometry.Scheme.Modules.overRestrictPresentation}
3323	  \uses{def:over_restrict_unit_iso, lem:over_restrict_pullback_iso, lem:presentation_map_mathlib}
3324	  \textit{A slice presentation yields a presentation of the geometric pullback.}
3325	  Let \(U \subseteq X\) be open and \(M\) a sheaf of modules on \(X\). A
3326	  presentation of the abstract Grothendieck-slice restriction \(M.\mathrm{over}\,U\)
3327	  yields a presentation of the geometric pullback \((U.\iota^{*})\,M\):
3328	  \[
3329	    (M.\mathrm{over}\,U).\mathrm{Presentation}
3330	      \;\longrightarrow\;
3331	    \bigl((U.\iota^{*})\,M\bigr).\mathrm{Presentation} .
3332	  \]
3333	\end{definition}
3334	\begin{proof}
3335	  \uses{def:over_restrict_unit_iso, lem:over_restrict_pullback_iso, lem:presentation_map_mathlib}
3336	  Apply the functorial transport of presentations \(\mathrm{Presentation.map}\)
3337	  (\cref{lem:presentation_map_mathlib}) along the step-3 slice equivalence functor
3338	  \((\mathrm{overRestrictEquiv}\,U).\mathrm{functor}\), using
3339	  \cref{def:over_restrict_unit_iso} to identify the image of the structure-sheaf
3340	  (unit) module with the target unit module; this lands a presentation of the
3341	  transported slice module
3342	  \((\mathrm{overRestrictEquiv}\,U).\mathrm{functor}.\mathrm{obj}\,(M.\mathrm{over}\,U)\).
3343	  Finally transport across the pullback packaging isomorphism
3344	  \((\mathrm{overRestrictEquiv}\,U).\mathrm{functor}.\mathrm{obj}\,(M.\mathrm{over}\,U)
3345	  \cong (U.\iota^{*})\,M\) (\cref{lem:over_restrict_pullback_iso}) via
3346	  \(\mathrm{Presentation.ofIsIso}\), giving a presentation of the geometric
3347	  pullback \((U.\iota^{*})\,M\).
3348	\end{proof}
