2808	  \label{lem:modules_pullback_mathlib}
2809	  \lean{AlgebraicGeometry.Scheme.Modules.pullback}
2810	  \mathlibok
2811	  \textit{Provided by Mathlib (\texttt{Mathlib.AlgebraicGeometry.Modules.Sheaf}).}
2812	  For a morphism of schemes \(f : X \to Y\), Mathlib supplies the pullback functor
2813	  \(f^{*} : Y.\mathrm{Modules} \to X.\mathrm{Modules}\) on sheaves of modules, left adjoint to
2814	  pushforward, hence colimit-preserving, and carrying the unit sheaf to the unit sheaf. The project
2815	  already uses this functor in the definition of local freeness. It is the geometric restriction
2816	  through which a presentation is transported to an open subscheme.
2817	\end{lemma}
